    },
    "id": {
      "type": "string",
      "pattern": "^[a-z0-9]+[a-z0-9._-]*$"
    },
    "agent_role": {
      "type": "string",
      "enum": [
        "triage_agent",
        "search_agent",
        "screening_agent",
        "dedupe_linker_agent",
        "extraction_agent",
        "trial_registry_agent",
        "classification_agent",
        "risk_of_bias_agent",
        "synthesis_agent",
